44	function avatarColor(seed: string): string {
45	  const colors = ['#4F9DF7', '#6B54C9', '#3F9A50', '#D24B83', '#DB6645', '#2589AB', '#239281', '#C8942A']
46	  let h = 0
47	  for (let i = 0; i < seed.length; i++) h = (h * 31 + seed.charCodeAt(i)) >>> 0
48	  return colors[h % colors.length]
49	}
